const today = new Date().toISOString().slice(0, 10);
const FEISHU_WEBHOOK = 'https://open.feishu.cn/open-apis/bot/v2/hook/2750a463-335f-4f9b-a227-b78087fa5db0';
return [{ json: { date: today, feishuWebhook: FEISHU_WEBHOOK } }];

const resp = $input.first().json;
const status = resp.statusCode || 0;
const body = resp.data || resp.body || '';
if (status !== 200 || !body || body.length < 100) return [{ json: { source: 'TechCrunch', items: [], error: `HTTP ${status}` } }];
const items = [];
const itemRegex = /<item[\s>]*([\s\S]*?)<\/item>/gi;
let match, count = 0;
while ((match = itemRegex.exec(body)) !== null && count < 10) {
  const xml = match[1];
  let title = '', link = '', desc = '', date = '', author = '';
  const t = xml.match(/<title>([\s\S]*?)<\/title>/i);
  if (t) title = t[1].replace(/<!\[CDATA\[([\s\S]*?)\]\]>/, '$1').trim();
  const l = xml.match(/<link>(.*?)<\/link>/i);
  if (l) link = l[1].trim();
  const d = xml.match(/<description>([\s\S]*?)<\/description>/i);
  if (d) { desc = d[1].replace(/<!\[CDATA\[([\s\S]*?)\]\]>/, '$1').replace(/<[^>]+>/g, ' ').substring(0, 200).trim(); }
  const p = xml.match(/<pubDate>(.*?)<\/pubDate>/i);
  if (p) date = p[1].trim();
  const c = xml.match(/<dc:creator>([\s\S]*?)<\/dc:creator>/i);
  if (c) author = c[1].replace(/<!\[CDATA\[([\s\S]*?)\]\]>/, '$1').trim();
  if (title) { items.push({ title, link, description: desc, date, author }); count++; }
}
return [{ json: { source: 'TechCrunch', items, count: items.length } }];

const resp = $input.first().json;
const status = resp.statusCode || 0;
const body = resp.data || resp.body || '';
if (status !== 200 || !body || body.length < 100) return [{ json: { source: 'HackerNews', items: [], error: `HTTP ${status}` } }];
const items = [];
const itemRegex = /<item[\s>]*([\s\S]*?)<\/item>/gi;
let match, count = 0;
while ((match = itemRegex.exec(body)) !== null && count < 10) {
  const xml = match[1];
  let title = '', link = '', desc = '', date = '', points = 0;
  const t = xml.match(/<title>([\s\S]*?)<\/title>/i);
  if (t) title = t[1].replace(/<!\[CDATA\[([\s\S]*?)\]\]>/, '$1').trim();
  const l = xml.match(/<link>(.*?)<\/link>/i);
  if (l) link = l[1].trim();
  const d = xml.match(/<description>([\s\S]*?)<\/description>/i);
  if (d) { desc = d[1].replace(/<!\[CDATA\[([\s\S]*?)\]\]>/, '$1').replace(/<[^>]+>/g, ' ').substring(0, 200).trim(); }
  const p = xml.match(/<pubDate>(.*?)<\/pubDate>/i);
  if (p) date = p[1].trim();
  const pm = desc.match(/Points:\s*(\d+)/);
  if (pm) points = parseInt(pm[1]);
  if (title) { items.push({ title, link, description: desc, date, points }); count++; }
}
return [{ json: { source: 'HackerNews', items, count: items.length } }];

const resp = $input.first().json;
const status = resp.statusCode || 0;
const body = resp.data || resp.body || '';
if (status !== 200 || !body || body.length < 100) return [{ json: { source: 'ProductHunt', items: [], error: `HTTP ${status}` } }];
const items = [];
const entryRegex = /<entry[\s>]*([\s\S]*?)<\/entry>/gi;
let match, count = 0;
while ((match = entryRegex.exec(body)) !== null && count < 10) {
  const xml = match[1];
  let title = '', link = '', desc = '';
  const t = xml.match(/<title>([\s\S]*?)<\/title>/i);
  if (t) title = t[1].trim();
  const l = xml.match(/<link[^>]*rel="alternate"[^>]*href="([^"]+)"/i);
  if (l) link = l[1];
  const c = xml.match(/<content[^>]*>([\s\S]*?)<\/content>/i);
  if (c) {
    desc = c[1].replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&');
    const pm = desc.match(/<p>(.*?)<\/p>/i);
    if (pm) desc = pm[1].trim();
    else desc = desc.replace(/<[^>]+>/g, ' ').substring(0, 200).trim();
  }
  if (title) { items.push({ title, link, description: desc }); count++; }
}
return [{ json: { source: 'ProductHunt', items, count: items.length } }];

