function cleanText(s){if(!s||typeof s!=='string')return '';return s.replace(/https?:\/\/[^\s]+/g,'').replace(/<[^>]+>/g,'').replace(/&\w+;/g,'').replace(/\n/g,' ').replace(/\s+/g,' ').trim();}
function isRealEnglish(t){if(!t||t.length<5)return false;const l=(t.match(/[a-zA-Z]/g)||[]).length;const tot=t.replace(/\s/g,'').length;return tot>0&&l>10&&(l/tot)>0.6;}
