const uniq=[...new Set(toTrans)];const bSize=30;const batches=[];for(let i=0;i<uniq.length;i+=bSize)batches.push(uniq.slice(i,i+bSize));
const tMap2={};for(let i=0;i<batches.length;i++){const b=batches[i];const prompt=`将以下${b.length}个英文翻译成中文，每行一个翻译结果：\n${b.map((t,j)=>`${j+1}. ${t}`).join('\n')}\n翻译结果：`;try{const r=await this.helpers.httpRequest({method:'POST',url:'http://192.168.31.102:11434/v1/chat/completions',headers:{'Content-Type':'application/json'},body:{model:'qwen2.5:3b',messages:[{role:'system',content:'你是科技资讯翻译助手。'},{role:'user',content:prompt}],temperature:0.1,max_tokens:2000,stream:false},timeout:720000});const content=r.choices?.[0]?.message?.content||'';const lines=content.split('\n').map(l=>l.replace(/^\d+[.\s]+/,'').trim()).filter(l=>l.length>0&&!l.includes('待翻译')&&!l.includes('翻译结果'));const mc=Math.min(b.length,lines.length);for(let j=0;j<mc;j++){if(lines[j]&&lines[j]!==b[j])tMap2[b[j]]=lines[j];}}catch(e){console.log(`批次 ${i+1} 错误: ${e.message}`);}}
let tc=0;tMap.forEach(p=>{const tr=tMap2[p.orig];if(tr){tc++;if(p.f==='title')allData[p.si].items[p.ii].title=tr;else{const ratio=tr.length/p.orig.length;const tl=Math.min(Math.floor(p.full.length*ratio*1.2),180);allData[p.si].items[p.ii].description=tr.substring(0,tl)+(tl<tr.length?'...':'');}}});
console.log(`回填: ${tc}/${tMap.length}`);
return allData.map(s=>({json:s}));

